$ErrorActionPreference='Stop';$root=(Resolve-Path (Join-Path $PSScriptRoot '..')).Path;. (Join-Path $root 'tests/helpers/TypedStudioFixture.ps1');$work=Join-Path ([IO.Path]::GetTempPath()) ('context-cache-'+[guid]::NewGuid().ToString('N'));New-Item -ItemType Directory $work|Out-Null
try{$p=New-TypedStudioFixture $work 'cache' -Approved -ExistingRepository; & "$root/scripts/Resolve-SpecialistPlan.ps1" -ProjectRoot $p -OutputPath (Join-Path $p '.studio/reports/specialist-plan.json')|Out-Null; & "$root/scripts/context/compile_context.ps1" -ProjectRoot $p -Role frontend-builder|Out-Null;$m=Get-Content -Raw (Join-Path $p '.studio/runtime/context/frontend-builder.json')|ConvertFrom-Json;if($m.cacheStatus -ne 'miss'){throw 'Expected first compile miss'};& "$root/scripts/context/compile_context.ps1" -ProjectRoot $p -Role frontend-builder|Out-Null;$m=Get-Content -Raw (Join-Path $p '.studio/runtime/context/frontend-builder.json')|ConvertFrom-Json;if($m.cacheStatus -ne 'hit'){throw 'Expected unchanged compile hit'};Add-Content (Join-Path $p '.studio/ACTIVE_AND_DEFERRED_SCOPE.md') 'timestamp-only body text';& "$root/scripts/context/compile_context.ps1" -ProjectRoot $p -Role frontend-builder|Out-Null;$m=Get-Content -Raw (Join-Path $p '.studio/runtime/context/frontend-builder.json')|ConvertFrom-Json;if($m.cacheStatus -eq 'hit'){throw 'Scope content mutation must invalidate'};& "$root/scripts/context/build_rule_route_index.ps1" -Check|Out-Null}finally{Remove-Item $work -Recurse -Force};Write-Host 'Context cache and routing assertions passed.'
